content:
在 location 里加上 try_files $uri $uri&#x2F; &#x2F;index.html;
具体配置如下：
server &#123;    listen       81;    server_name  project_mall;    #charset koi8-r;    #access_log  logs/host.access.log  main;    location / &#123;    root   study/project_mall;    index  index.html index.htm;    # 解决单页面应用刷新出现403或者404错误    try_files  $uri $uri/ /index.html;    &#125;&#125;

前端项目存储位置&#x2F;usr&#x2F;local&#x2F;webserver&#x2F;nginx&#x2F;project&#x2F;crtoms
配置 0（推荐）
server&#123;        listen 9005; ## nginx监听端口号        location / &#123;                root project/crtoms; # project在ngxin目录下，和html同级                try_files $uri $uri/ /index.html;        &#125;        # 前端代理        location /api/ &#123; #api是同一请求后缀             proxy_pass http://192.168.10.235:8888/; #后台内网地址        &#125;&#125;

假设服务器 ip 为 192.168.10.234那么此时访问方式就是 http:192.168.10.234:9095&#x2F;
配置 1
server&#123;        listen 9005; ## nginx监听端口号        location / &#123;                alias /usr/local/webserver/nginx/project/crtoms/;                index index.html index.htm;        &#125;&#125;

假设服务器 ip 为 192.168.10.234那么此时访问方式就是 http:192.168.10.234:9095&#x2F;
配置 2
server&#123;        listen 9005; ## nginx监听端口号        location /crtoms &#123;                alias /usr/local/webserver/nginx/project/crtoms/;                index index.html index.htm;        &#125;&#125;

假设服务器 ip 为 192.168.10.234那么此时访问方式就是 http:192.168.10.234:9095&#x2F;crtoms
配置 3
server&#123;        listen 9005; ## nginx监听端口号        location /crtoms &#123;                root /usr/local/webserver/nginx/project/;                index index.html index.htm;        &#125;&#125;

假设服务器 ip 为 192.168.10.234那么此时访问方式就是 http:192.168.10.234:9095&#x2F;crtoms

alias 是一个目录别名的定义，root 则是上层目录的定义alias 后面必须要用“&#x2F;”结束，否则会找不到文件的。而 root 则可有可无。

前提：nginx 需要安装 mp4 模块假设服务器 ip 为 192.168.10.234
播放 mp4 视频server &#123;       listen       80;       location /securityMp4 &#123;           alias /home/DevelopKit/FILE/securityFile/;           mp4;           mp4_buffer_size       1m;           mp4_max_buffer_size   2000m;           # mp4_limit_rate        on;           # mp4_limit_rate_after  30s;           limit_rate 260k;           limit_rate_after 3m;       &#125;&#125;

假设存在文件&#x2F;home&#x2F;DevelopKit&#x2F;FILE&#x2F;securityFile&#x2F;a.mp4那么访问 192.168.10.234:80&#x2F;securityMp4&#x2F;a.mp4 就能播放视频
播放 ts-m3u8 视频server &#123;       listen       80;       location /securityHls &#123;           alias /home/DevelopKit/FILE/securityFile/;           types &#123;               application/vnd.apple.mpegurl m3u8;               video/mp2t ts;           &#125;           add_header Cache-Control no-cache;           add_header &#x27;Access-Control-Allow-Origin&#x27; &#x27;*&#x27;;       &#125;&#125;

假设存在文件&#x2F;home&#x2F;DevelopKit&#x2F;FILE&#x2F;securityFile&#x2F;test_0.ts假设存在文件&#x2F;home&#x2F;DevelopKit&#x2F;FILE&#x2F;securityFile&#x2F;test_1.ts假设存在文件&#x2F;home&#x2F;DevelopKit&#x2F;FILE&#x2F;securityFile&#x2F;test.m3u8那么访问 192.168.10.234:80&#x2F;securityMp4&#x2F;test.m3u8 就能播放视频

实例：接口
/**     * selectOverrunData:查询一个单次计划某个行别某个速度级下各个超限类型的占比     *     * @param testTaskId 测试任务id     * @param xb         行别     * @param speedLevel 速度级     * @param type       超限还是大值     * @param labelList  通道名称集合     * @return     * @author Zhangyuhan     * @date 2021/7/8 15:03     */    List&lt;Map&lt;String, Object&gt;&gt; selectStatisticalInformation(@Param(&quot;testTaskId&quot;) String testTaskId,                                                           @Param(&quot;xb&quot;) String xb,                                                           @Param(&quot;speedLevel&quot;) Integer speedLevel,                                                           @Param(&quot;type&quot;) String type,                                                           @Param(&quot;labelList&quot;) List&lt;String&gt; labelList);

接口对应的 sql
&lt;select id=&quot;selectStatisticalInformation&quot; resultType=&quot;map&quot;&gt;        &lt;foreach collection=&quot;labelList&quot; item=&quot;item&quot; index=&quot;index&quot; separator=&quot;UNION&quot;&gt;        SELECT numtab.num AS VALUE,        concat( round(( numtab.num / numtab.total ) * 100, 2),&#x27;%&#x27; ) AS NAME        FROM            (            SELECT            &lt;if test=&#x27;type == &quot;超限&quot;&#x27;&gt;                count( CASE WHEN cxlx = #&#123;item&#125; THEN 1 END ) AS num ,            &lt;/if&gt;            &lt;if test=&#x27;type == &quot;大值&quot;&#x27;&gt;                count( CASE WHEN dzlx = #&#123;item&#125; THEN 1 END ) AS num,            &lt;/if&gt;            count(*) AS total            FROM            &lt;if test=&#x27;type == &quot;超限&quot;&#x27;&gt;            cxdata_table            &lt;/if&gt;            &lt;if test=&#x27;type == &quot;大值&quot;&#x27;&gt;            dzdata_table            &lt;/if&gt;            WHERE            dcjh_id = &#x27;797cb0e7de3241029b5feb6b1ffa17ca&#x27;            AND xb = &#x27;上行&#x27;            &lt;if test=&#x27;type == &quot;超限&quot;&#x27;&gt;            AND flag = &#x27;0&#x27;            &lt;/if&gt;            ) numtab        &lt;/foreach&gt;    &lt;/select&gt;

mybatis 映射文件中，if 标签判断字符串相等，两种方式：
因为 mybatis 映射文件，是使用的 ognl 表达式，所以在判断字符串 sex 变量是否是字符串 Y 的时候，
&lt;if test=&quot;sex==&#x27;Y&#x27;.toString()&quot;&gt;&lt;if test = &#x27;sex== &quot;Y&quot;&#x27;&gt;

注意：不能使用
&lt;if test=&quot;sex==&#x27;Y&#x27;&quot;&gt;and 1=1&lt;/if&gt;

因为 mybatis 会把’Y’解析为字符，所以不能这样写 会报 NumberFormatException
MyBatis 是使用的 OGNL 表达式来进行解析的，这个地方有一个坑需要注意下，单引号内有一个字符的情况下，OGNL 会将其以 java 中的 char 类型进行解析，那么此时 char 类型与参数 String 类型用等号进行比较的时候结果都是 false。解决方案也很简单，就是讲 test 中的单个字符用双引号括起来。
&lt;where&gt;      	/*不行*/          &lt;if test=&quot;qryStr==&#x27;Y&#x27;&quot;&gt;              and counts=1          &lt;/if&gt;           /*可以*/          &lt;if test=&quot;qryStr==&#x27;Y&#x27;.toString()&quot;&gt;              and counts=1          &lt;/if&gt;              /*可以*/          &lt;if test=&#x27;qryStr==&quot;Y&quot;&#x27;&gt;              and counts=2          &lt;/if&gt;      &lt;/where&gt;

建议使用外部单引号，里面双引号嵌套的方式。

动态 SQL 是 MyBatis 的强大特性之一。在 JDBC 或其它类似的框架中，开发人员通常需要手动拼接 SQL 语句。根据不同的条件拼接 SQL 语句是一件极其痛苦的工作。例如，拼接时要确保添加了必要的空格，还要注意去掉列表最后一个列名的逗号。而动态 SQL 恰好解决了这一问题，可以根据场景动态的构建查询。
动态SQL（code that is executed dynamically），它一般是根据用户输入或外部条件动态组合的SQL语句块。动态SQL能灵活的发挥SQL强大的功能、方便的解决一些其它方法难以解决的问题。相信使用过动态SQL的人都能体会到它带来的便利，然而动态SQL有时候在执行性能 (效率)上面不如静态SQL，而且使用不恰当，往往会在安全方面存在隐患 (SQL 注入式攻击)。
MyBatis动态 sql 的特性Mybatis 动态 sql 是做什么的?Mybatis 动态 sql 可以让我们在 Xml 映射文件内，以标签的形式编写动态 sql，完成逻辑判断和动态拼接 sql 的功能。
Mybatis 的 9 种 动 态 sql 标 签有哪些？
动态 sql 的执行原理？原理为：使用 OGNL 从 sql 参数对象中计算表达式的值，根据表达式的值动态拼接 sql，以此来完成动态 sql 的功能。
MyBatis标签if标签：条件判断MyBatis if 类似于 Java 中的 if 语句，是 MyBatis 中最常用的判断语句。使用 if 标签可以节省许多拼接 SQL 的工作，把精力集中在 XML 的维护上。
if 语句使用方法简单，常常与 test 属性联合使用。语法如下:
&lt;if test=&quot;判断条件&quot;&gt;    SQL语句&lt;/if&gt;

不使用动态sql&lt;select id=&quot;selectUserByUsernameAndSex&quot;        resultType=&quot;user&quot; parameterType=&quot;com.ys.po.User&quot;&gt;    &lt;!-- 这里和普通的sql 查询语句差不多，对于只有一个参数，后面的 #&#123;id&#125;表示占位符，里面          不一定要写id,         写啥都可以，但是不要空着，如果有多个参数则必须写pojo类里面的属性 --&gt;    select * from user where username=#&#123;username&#125; and sex=#&#123;sex&#125;&lt;/select&gt;

使用动态sql上面的查询语句，我们可以发现，如果 #{username} 为空，那么查询结果也是空，如何解决这个问题呢？使用 if 来判断，可多个 if 语句同时使用。
以下语句表示为可以按照网站名称（name）或者网址（url）进行模糊查询。如果您不输入名称或网址，则返回所有的网站记录。但是，如果你传递了任意一个参数，它就会返回与给定参数相匹配的记录。
&lt;select id=&quot;selectAllWebsite&quot; resultMap=&quot;myResult&quot;&gt;      select id,name,url from website     where 1=1       &lt;if test=&quot;name != null&quot;&gt;               AND name like #&#123;name&#125;      &lt;/if&gt;       &lt;if test=&quot;url!= null&quot;&gt;               AND url like #&#123;url&#125;       &lt;/if&gt;&lt;/select&gt;

where+if标签where、if同时使用可以进行查询、模糊查询
注意，&lt;if&gt;失败后， &lt;where&gt; 关键字只会去掉库表字段赋值前面的and，不会去掉语句后面的and关键字，即注意，&lt;where&gt; 只会去掉&lt;if&gt; 语句中的最开始的and关键字。所以下面的形式是不可取的
&lt;select id=&quot;findQuery&quot; resultType=&quot;Student&quot;&gt;    &lt;include refid=&quot;selectvp&quot;/&gt;    &lt;where&gt;        &lt;if test=&quot;sacc != null&quot;&gt;            sacc like concat(&#x27;%&#x27; #&#123;sacc&#125; &#x27;%&#x27;)        &lt;/if&gt;        &lt;if test=&quot;sname != null&quot;&gt;            AND sname like concat(&#x27;%&#x27; #&#123;sname&#125; &#x27;%&#x27;)        &lt;/if&gt;        &lt;if test=&quot;sex != null&quot;&gt;            AND sex=#&#123;sex&#125;        &lt;/if&gt;        &lt;if test=&quot;phone != null&quot;&gt;            AND phone=#&#123;phone&#125;        &lt;/if&gt;    &lt;/where&gt;&lt;/select&gt;

这个“where”标签会知道如果它包含的标签中有返回值的话，它就插入一个‘where’。此外，如果标签返回的内容是以AND 或OR 开头的，则它会剔除掉。
set标签set可以用来修改
&lt;update id=&quot;upd&quot;&gt;    update student    &lt;set&gt;        &lt;if test=&quot;sname != null&quot;&gt;sname=#&#123;sname&#125;,&lt;/if&gt;        &lt;if test=&quot;spwd != null&quot;&gt;spwd=#&#123;spwd&#125;,&lt;/if&gt;        &lt;if test=&quot;sex != null&quot;&gt;sex=#&#123;sex&#125;,&lt;/if&gt;        &lt;if test=&quot;phone != null&quot;&gt;phone=#&#123;phone&#125;&lt;/if&gt;    &lt;/set&gt;    where sid=#&#123;sid&#125;&lt;/update&gt;

choose(when,otherwise) 语句有时候，我们不想用到所有的查询条件，只想选择其中的一个，查询条件有一个满足即可，使用 choose 标签可以解决此类问题，类似于 Java 的 switch 语句
&lt;select id=&quot;selectUserByChoose&quot; resultType=&quot;com.ys.po.User&quot; parameterType=&quot;com.ys.po.User&quot;&gt;      select * from user      &lt;where&gt;          &lt;choose&gt;              &lt;when test=&quot;id !=&#x27;&#x27; and id != null&quot;&gt;                  id=#&#123;id&#125;              &lt;/when&gt;              &lt;when test=&quot;username !=&#x27;&#x27; and username != null&quot;&gt;                  and username=#&#123;username&#125;              &lt;/when&gt;              &lt;otherwise&gt;                  and sex=#&#123;sex&#125;              &lt;/otherwise&gt;          &lt;/choose&gt;      &lt;/where&gt;  &lt;/select&gt;

也就是说，这里我们有三个条件，id、username、sex，只能选择一个作为查询条件

如果 id 不为空，那么查询语句为：select * from user where id&#x3D;?
如果 id 为空，那么看username 是否为空，如果不为空，那么语句为 select * from user where username&#x3D;?;
如果 username 为空，那么查询语句为 select * from user where sex&#x3D;?

trimtrim标记是一个格式化的标记，可以完成set或者是where标记的功能
用 trim 改写上面第二点的 if+where 语句&lt;select id=&quot;selectUserByUsernameAndSex&quot; resultType=&quot;user&quot; parameterType=&quot;com.ys.po.User&quot;&gt;    select * from user    &lt;!-- &lt;where&gt;        &lt;if test=&quot;username != null&quot;&gt;           username=#&#123;username&#125;        &lt;/if&gt;                 &lt;if test=&quot;username != null&quot;&gt;           and sex=#&#123;sex&#125;        &lt;/if&gt;    &lt;/where&gt;  --&gt;    &lt;trim prefix=&quot;where&quot; prefixOverrides=&quot;and | or&quot;&gt;        &lt;if test=&quot;username != null&quot;&gt;           and username=#&#123;username&#125;        &lt;/if&gt;        &lt;if test=&quot;sex != null&quot;&gt;           and sex=#&#123;sex&#125;        &lt;/if&gt;    &lt;/trim&gt;&lt;/select&gt;


prefix：前缀
prefixoverride：去掉第一个and或者是or

用 trim 改写上面第三点的 if+set 语句&lt;!-- 根据 id 更新 user 表的数据 --&gt;&lt;update id=&quot;updateUserById&quot; parameterType=&quot;com.ys.po.User&quot;&gt;    update user u        &lt;!-- &lt;set&gt;            &lt;if test=&quot;username != null and username != &#x27;&#x27;&quot;&gt;                u.username = #&#123;username&#125;,            &lt;/if&gt;            &lt;if test=&quot;sex != null and sex != &#x27;&#x27;&quot;&gt;                u.sex = #&#123;sex&#125;            &lt;/if&gt;        &lt;/set&gt; --&gt;        &lt;trim prefix=&quot;set&quot; suffixOverrides=&quot;,&quot;&gt;            &lt;if test=&quot;username != null and username != &#x27;&#x27;&quot;&gt;                u.username = #&#123;username&#125;,            &lt;/if&gt;            &lt;if test=&quot;sex != null and sex != &#x27;&#x27;&quot;&gt;                u.sex = #&#123;sex&#125;,            &lt;/if&gt;        &lt;/trim&gt;          where id=#&#123;id&#125;&lt;/update&gt;


suffix：后缀
suffixoverride：去掉最后一个逗号（也可以是其他的标记，就像是上面前缀中的and一样）

trim+if同时使用可以实现插入功能&lt;insert id=&quot;add&quot;&gt;    insert  into student    &lt;trim prefix=&quot;(&quot; suffix=&quot;)&quot; suffixOverrides=&quot;,&quot;&gt;        &lt;if test=&quot;sname != null&quot;&gt;sname,&lt;/if&gt;        &lt;if test=&quot;spwd != null&quot;&gt;spwd,&lt;/if&gt;        &lt;if test=&quot;sex != null&quot;&gt;sex,&lt;/if&gt;        &lt;if test=&quot;phone != null&quot;&gt;phone,&lt;/if&gt;    &lt;/trim&gt;    &lt;trim prefix=&quot;values (&quot; suffix=&quot;)&quot;  suffixOverrides=&quot;,&quot;&gt;        &lt;if test=&quot;sname != null&quot;&gt;#&#123;sname&#125;,&lt;/if&gt;        &lt;if test=&quot;spwd != null&quot;&gt;#&#123;spwd&#125;,&lt;/if&gt;        &lt;if test=&quot;sex != null&quot;&gt;#&#123;sex&#125;,&lt;/if&gt;        &lt;if test=&quot;phone != null&quot;&gt;#&#123;phone&#125;&lt;/if&gt;    &lt;/trim&gt;&lt;/insert&gt;

foreachforeach是用来对集合的遍历，这个和Java中的功能很类似。通常处理SQL中的in语句。
foreach 元素的功能非常强大，它允许你指定一个集合，声明可以在元素体内使用的集合项（item）和索引（index）变量。它也允许你指定开头与结尾的字符串以及集合项迭代之间的分隔符。这个元素也不会错误地添加多余的分隔符
你可以将任何可迭代对象（如 List、Set 等）、Map 对象或者数组对象作为集合参数传递给 foreach。当使用可迭代对象或者数组时，index 是当前迭代的序号，item 的值是本次迭代获取到的元素。当使用 Map 对象（或者 Map.Entry 对象的集合）时，index 是键，item 是值。
//批量查询&lt;select id=&quot;findAll&quot; resultType=&quot;Student&quot; parameterType=&quot;Integer&quot;&gt;    select  *  from  student WHERE sid in    &lt;foreach item=&quot;ids&quot; collection=&quot;array&quot;  open=&quot;(&quot; separator=&quot;,&quot; close=&quot;)&quot;&gt;        #&#123;ids&#125;    &lt;/foreach&gt;&lt;/select&gt;//批量删除&lt;delete id=&quot;del&quot;  parameterType=&quot;Integer&quot;&gt;    delete  from  student  where  sid in    &lt;foreach item=&quot;ids&quot; collection=&quot;array&quot;  open=&quot;(&quot; separator=&quot;,&quot; close=&quot;)&quot;&gt;        #&#123;ids&#125;    &lt;/foreach&gt;&lt;/delete&gt;

sql在实际开发中会遇到许多相同的SQL，比如根据某个条件筛选，这个筛选很多地方都能用到，我们可以将其抽取出来成为一个公用的部分，这样修改也方便，一旦出现了错误，只需要改这一处便能处处生效了，此时就用到了&lt;sql&gt;这个标签了。
当多种类型的查询语句的查询字段或者查询条件相同时，可以将其定义为常量，方便调用。为求&lt;select&gt;结构清晰也可将 sql 语句分解。
&lt;sql id=&quot;selectvp&quot;&gt;    select  *  from  student&lt;/sql&gt;

include这个标签和&lt;sql&gt;是天仙配，是共生的，include用于引用sql标签定义的常量。比如引用上面sql标签定义的常量
refid这个属性就是指定&lt;sql&gt;标签中的id值（唯一标识）
&lt;select id=&quot;findbyid&quot;  resultType=&quot;student&quot;&gt;    &lt;include refid=&quot;selectvp&quot;/&gt;    WHERE 1=1    &lt;if test=&quot;sid != null&quot;&gt;        AND sid like #&#123;sid&#125;    &lt;/if&gt;&lt;/select&gt;

引用其他XML中的SQL片段比如你在com.xxx.dao.xxMapper这个Mapper的XML中定义了一个SQL片段如下：
&lt;sql id=&quot;Base_Column_List&quot;&gt; ID,MAJOR,BIRTHDAY,AGE,NAME,HOBBY&lt;/sql&gt;

此时我在com.xxx.dao.PatinetMapper中的XML文件中需要引用，如下：
&lt;include refid=&quot;com.xxx.dao.xxMapper.Base_Column_List&quot;&gt;&lt;/include&gt;

整合案例xml
&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot; ?&gt;&lt;!DOCTYPE mapper        PUBLIC &quot;-//mybatis.org//DTD Mapper 3.0//EN&quot;        &quot;http://mybatis.org/dtd/mybatis-3-mapper.dtd&quot;&gt;&lt;mapper namespace=&quot;com.yzx.mapper.StuMapper&quot;&gt;    &lt;sql id=&quot;selectvp&quot;&gt;        select  *  from  student    &lt;/sql&gt;        &lt;select id=&quot;find&quot; resultType=&quot;Student&quot;&gt;        &lt;include refid=&quot;selectvp&quot;/&gt;    &lt;/select&gt;    &lt;select id=&quot;findbyid&quot;  resultType=&quot;student&quot;&gt;        &lt;include refid=&quot;selectvp&quot;/&gt;        WHERE 1=1        &lt;if test=&quot;sid != null&quot;&gt;            AND sid like #&#123;sid&#125;        &lt;/if&gt;    &lt;/select&gt;        &lt;select id=&quot;findQuery&quot; resultType=&quot;Student&quot;&gt;            &lt;include refid=&quot;selectvp&quot;/&gt;            &lt;where&gt;                &lt;if test=&quot;sacc != null&quot;&gt;                    sacc like concat(&#x27;%&#x27; #&#123;sacc&#125; &#x27;%&#x27;)                &lt;/if&gt;                &lt;if test=&quot;sname != null&quot;&gt;                    AND sname like concat(&#x27;%&#x27; #&#123;sname&#125; &#x27;%&#x27;)                &lt;/if&gt;                &lt;if test=&quot;sex != null&quot;&gt;                    AND sex=#&#123;sex&#125;                &lt;/if&gt;                &lt;if test=&quot;phone != null&quot;&gt;                    AND phone=#&#123;phone&#125;                &lt;/if&gt;            &lt;/where&gt;        &lt;/select&gt;    &lt;update id=&quot;upd&quot;&gt;        update student        &lt;set&gt;            &lt;if test=&quot;sname != null&quot;&gt;sname=#&#123;sname&#125;,&lt;/if&gt;            &lt;if test=&quot;spwd != null&quot;&gt;spwd=#&#123;spwd&#125;,&lt;/if&gt;            &lt;if test=&quot;sex != null&quot;&gt;sex=#&#123;sex&#125;,&lt;/if&gt;            &lt;if test=&quot;phone != null&quot;&gt;phone=#&#123;phone&#125;&lt;/if&gt; 