@Configurationpublic class Config &#123;    Logger logger = LoggerFactory.getLogger(Config.class);    private final String error_topic=&quot;error_topic&quot;;    @Bean    public ConcurrentKafkaListenerContainerFactory listenerContainerFactory(ConsumerFactory consumerFactory, KafkaTemplate&lt;String,Object&gt; template) &#123;        ConcurrentKafkaListenerContainerFactory factory = new ConcurrentKafkaListenerContainerFactory();        factory.setConsumerFactory(consumerFactory);        // 最大重试次数5次，每次间隔5s(该配置需要参考 Broker.leader 切换的平均时间去设置)        SeekToCurrentErrorHandler seekToCurrentErrorHandler = new SeekToCurrentErrorHandler((consumerRecord, e) -&gt; &#123;            logger.error(&quot;重试机制后异常，consumerRecord：&#123;&#125;&quot;, consumerRecord.toString(), e);            //做其他业务操作，如记录异常信息到表，发送信息到其他的队列人工核对处理等            template.send(error_topic,consumerRecord.toString());        &#125;, new FixedBackOff(5000, 5));//       批量获取消息的时候，使用该方式//        SeekToCurrentBatchErrorHandler batchErrorHandler = new SeekToCurrentBatchErrorHandler();        factory.setErrorHandler(seekToCurrentErrorHandler);        //设置提交偏移量的方式 ,否则出现异常的时候, 会报错No Acknowledgment available as an argument, the listener container must have a MANUAL AckMode to populate the Acknowledgment.        factory.getContainerProperties().setAckMode(ContainerProperties.AckMode.MANUAL_IMMEDIATE);        return factory;    &#125;&#125;

