两个日期之间相差的天数，日期为单位（比如相差两秒，可能就相差一天，12:23:59：59 和 13:01:00：00 就相差一天）/**     * date2比date1多的天数     * @param date1     * @param date2     * @return     */private static int differentDays(Date date1,Date date2) &#123;  Calendar cal1 = Calendar.getInstance();  cal1.setTime(date1);  Calendar cal2 = Calendar.getInstance();  cal2.setTime(date2);  int day1= cal1.get(Calendar.DAY_OF_YEAR);  int day2 = cal2.get(Calendar.DAY_OF_YEAR);  int year1 = cal1.get(Calendar.YEAR);  int year2 = cal2.get(Calendar.YEAR);  if(year1 != year2) &#123;//同一年    int timeDistance = 0 ;    for(int i = year1 ; i &lt; year2 ; i ++)    &#123;      if(i%4==0 &amp;&amp; i%100!=0 || i%400==0)    //闰年      &#123;        timeDistance += 366;      &#125;      else    //不是闰年      &#123;        timeDistance += 365;      &#125;    &#125;    return timeDistance + (day2-day1) ;  &#125; else &#123;// 不同年    System.out.println(&quot;判断day2 - day1 : &quot; + (day2-day1));    return day2-day1;  &#125;&#125;

两个日期之间相差的天数，以毫秒数精确计算（比如相差 22 小时可能是同一天）/**     * 通过秒毫秒数判断两个时间的间隔的天数     * @param date1     * @param date2     * @return     */public static int differentDaysByMillisecond(Date date1,Date date2)&#123;  int days = (int) ((date2.getTime() - date1.getTime()) / (1000*3600*24));  return days;&#125;

