场景项目需要 导入一批数据，对数据进行切割，用多线程跑。
问题点方法上增加@Transactional，对多线程无效，发生异常，子线程不会回滚，即使在子线程中增加@Transactional。原因：线程不归spring容器管理，也就不指望通知回滚了。
代码将大数据进行切割 // apache自带切割api, num是对应想要切几段ListUtils.partition(list, num);
使用异常标志、发令枪控制各线程回滚@Transactional(rollbackFor = Exception.class)public Result&lt;String&gt; dealData(int sheetMergeCount) &#123;		// todo 业务逻辑...		// 切割数据        List&lt;List&lt;Integer&gt;&gt; list = splitList(sheetMergeCount, 10);        // 异常标志，AtomicBoolean保证线程安全        AtomicBoolean isError = new AtomicBoolean(false);        // 发令枪，长度是切割的子集合数量(线程的数量)        CountDownLatch countDownLatch = new CountDownLatch(list.size());        for (List&lt;Integer&gt; integerList : list) &#123;        	// 将任务放进线程池            ThreadPoolUtil.exec(() -&gt; &#123;            	// 将事务操作放在新的类中，并开启事务                extraService.upload(integerList, isError, countDownLatch);            &#125;);        &#125;        try &#123;        	// 等所有线程都跑完，判断异常标识，有异常，进行主线程内回滚            countDownLatch.await();            if (isError.get()) &#123;            	// 手动回滚            	TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();                return Result.fail(&quot;系统异常，稍后重试&quot;);            &#125;            return Result.success(&quot;success&quot;);        &#125; catch (Exception e) &#123;	        TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();            log.error(&quot;dealData发令枪异常&quot;, e);        &#125;        return Result.fail(&quot;系统异常，稍后重试&quot;);    &#125;

@Service@Slf4jpublic class ExtraServiceImpl implements ExtraService &#123;    @Override    @Transactional(rollbackFor = Exception.class)    public void uploadData(List&lt;Integer&gt; integerList, AtomicBoolean isError, CountDownLatch countDownLatch) &#123;        try &#123;            // todo 业务逻辑        &#125; catch (Exception e) &#123;            log.error(&quot;ExtraService.uploadData异常&quot;, e);            // 发生异常，进行标记            isError.set(true);        &#125; finally &#123;        	// 发令枪倒计时            countDownLatch.countDown();        &#125;        try &#123;        	// 等所有线程都跑完，判断异常标识，有异常，线程内进行回滚            countDownLatch.await();            if (isError.get()) &#123;                // 手动回滚                TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();            &#125;        &#125; catch (Exception e) &#123;            log.error(&quot;ExtraService.uploadData发令枪异常&quot;, e);            // 手动回滚            TransactionAspectSupport.currentTransactionStatus().setRollbackOnly();        &#125;    &#125;&#125;

