需求：一个大的区段有小半径曲线段，复合曲线，平曲线和竖曲线各个不同数量不同长度的多个区段这些区段可能覆盖，交叉或完全不重叠
求：不与任意特殊区段有关联的多个直线段
公共方法：
public List&lt;ImportSectionVO&gt; filterQd(List&lt;ImportSectionVO&gt; filterList, List&lt;ImportSectionVO&gt; zxdList, String name) &#123;    ImportSectionVO zxd;    ImportSectionVO filter;    for (int i = 0; i &lt; filterList.size(); i++) &#123;        filter = filterList.get(i);        for (int j = zxdList.size() - 1; j &gt;= 0; j--) &#123;            zxd = zxdList.get(j);            if (filter.getEndMile() &lt;= zxd.getStartMile() || filter.getStartMile() &gt;= zxd.getEndMile()) &#123;                continue;            &#125; else if (filter.getStartMile() &lt;= zxd.getStartMile() &amp;&amp; filter.getEndMile() &gt;= zxd.getEndMile()) &#123;                zxdList.remove(j);            &#125; else if (filter.getStartMile() &gt;= zxd.getStartMile() &amp;&amp; filter.getEndMile() &lt;= zxd.getEndMile()) &#123;                zxdList.remove(j);                zxdList.add(j, new ImportSectionVO(name, zxd.getStartMile(), filter.getStartMile()));                zxdList.add(j + 1, new ImportSectionVO(name, filter.getEndMile(), zxd.getEndMile()));                j += 2;            &#125; else if (filter.getStartMile() &gt; zxd.getStartMile() &amp;&amp; filter.getStartMile() &lt; zxd.getEndMile()) &#123;                zxdList.remove(j);                zxdList.add(new ImportSectionVO(name, zxd.getStartMile(), filter.getStartMile()));                j += 1;            &#125; else if (filter.getEndMile() &gt; zxd.getStartMile() &amp;&amp; filter.getEndMile() &lt; zxd.getEndMile()) &#123;                zxdList.remove(j);                zxdList.add(new ImportSectionVO(name, filter.getEndMile(), zxd.getEndMile()));                j += 1;            &#125;        &#125;    &#125;    return zxdList;&#125;

