public List&lt;List&lt;ImportSectionVO&gt;&gt; selectXlxx(String xianbie, String xingbie, Double startMile, Double endMile) &#123;    List&lt;List&lt;ImportSectionVO&gt;&gt; res = new ArrayList&lt;&gt;();    // 顺序依次是竖曲线，平曲线，复合曲线，小半径曲线    List&lt;ImportSectionVO&gt; sqx = baseMapper.selectSqx(xianbie,            xingbie,            startMile,            endMile);    List&lt;ImportSectionVO&gt; pqx = baseMapper.selectPqx(xianbie,            xingbie,            startMile,            endMile);    List&lt;ImportSectionVO&gt; fhqx = baseMapper.selectFhqx(xianbie,            xingbie,            startMile,            endMile);    List&lt;ImportSectionVO&gt; xbjqx = baseMapper.selectSmallRadiusSection(xianbie,            xingbie,            startMile,            endMile);    String name = &quot;复合曲线&quot;;    fhqx = filterQd(xbjqx, fhqx, name);    name = &quot;平曲线&quot;;    pqx = filterQd(xbjqx, pqx, name);    pqx = filterQd(fhqx, pqx, name);    name = &quot;竖曲线&quot;;    sqx = filterQd(xbjqx, sqx, name);    sqx = filterQd(fhqx, sqx, name);    sqx = filterQd(pqx, sqx, name);    // 直线段：筛选出所有不是任何特殊区段的区段就是直线段    List&lt;ImportSectionVO&gt; zxd = new ArrayList&lt;&gt;();    name = &quot;直线段&quot;;    zxd.add(new ImportSectionVO(name, startMile, endMile));    filterQd(xbjqx, zxd, name);    filterQd(fhqx, zxd, name);    filterQd(pqx, zxd, name);    filterQd(sqx, zxd, name);    res.add(sqx);    res.add(pqx);    res.add(fhqx);    res.add(xbjqx);    res.add(zxd);    return res;&#125;

