let formData = new FormData()// 这里的file对象可以用其他的框架上传插件来获取，比如layui的或者bootstrap的,或者只是input type=&#x27;file&#x27;的等等等等。// 这里只是获取到文件对象，并不用框架来上传，真正上传文件还在下面的代码中formData.append(&#x27;file&#x27;, file) // 这里的这个file就是前台的文件对象，后台用MultipartFile类接收的formData.append(&#x27;fileInfo&#x27;, fileInfo)formData.append(&#x27;id&#x27;, newId)let aj = &#123;  //上传文件数据  url: Hussar.ctxPath + &#x27;/dtjcResources/uploadFile&#x27;,  type: &#x27;POST&#x27;,  cache: false,  data: formData,  processData: false,  contentType: false,  async: true,  xhr() &#123;    let xhr = new XMLHttpRequest()    xhr.upload.addEventListener(&#x27;progress&#x27;, (e) =&gt; &#123;      let progressRate = Math.round((e.loaded / e.total) * 100) + &#x27;%&#x27; // 获取到百分比      $(&quot;[fileId=&#x27;&quot; + domId + &quot;&#x27;] .progress_num&quot;).text(progressRate) // 让前台的dom元素显示这个百分比    &#125;)    return xhr  &#125;,  success(res) &#123;    if (res.code == &#x27;200&#x27;) &#123;      $(&quot;[fileId=&#x27;&quot; + domId + &quot;&#x27;] .file_progress&quot;).text(&#x27;上传成功&#x27;)    &#125; else &#123;      $(&quot;[fileId=&#x27;&quot; + domId + &quot;&#x27;] .file_progress&quot;).text(&#x27;上传失败&#x27;)    &#125;  &#125;,  error() &#123;    $(&quot;[fileId=&#x27;&quot; + domId + &quot;&#x27;] .file_progress&quot;).text(&#x27;上传失败&#x27;)  &#125;&#125;$.ajax(aj)
