返回整体文件流，通过浏览器转成二进制触发下载该方式和传统的方式不同。
传统是读取服务器返回的流，这里是服务器流都已经整体返回了，然后才通过 js 转成文件触发下载
该方式只适合下载小文件（一般是小于 10M），如果文件过大，会导致浏览器占用内存过大，页面崩溃
以下载 excel 为例子
前台代码
/** * 下载数据导入模板 */export function downloadImportTemplate(url, fileName) &#123;  return request(&#123;    type: &#x27;get&#x27;,    url,    responseType: &#x27;blob&#x27;  &#125;).then((res) =&gt; &#123;    const url = window.URL.createObjectURL(new Blob([res]))    const link = document.createElement(&#x27;a&#x27;)    link.style.display = &#x27;none&#x27;    link.href = url    link.setAttribute(&#x27;download&#x27;, fileName + &#x27;.xlsx&#x27;)    document.body.appendChild(link)    link.click()  &#125;)&#125;// 其他地方只需引入该方法，调用传入参数即可downloadImportTemplate(&#x27;/downloadTemplate&#x27;, &#x27;工程车辆导入模板&#x27;)

@RequestMapping(&quot;/downloadTemplate&quot;)public void downLoadEngineeringVehiclesImportTemplateFile(HttpServletResponse response) &#123;    downLoadTemplate(&quot;工程车导入模板&quot;, response);&#125;public void downLoadTemplate(String name, HttpServletResponse response) &#123;    String path = &quot;template/&quot; + name + &quot;.xlsx&quot;;    // 创建缓冲区    byte[] buffer = new byte[1024];// 缓冲区大小1k    int len = 0;    // 重点就是获取输入流和输出流，还有设置请求头    try (InputStream in = this.getClass().getClassLoader().getResourceAsStream(path);         OutputStream out = response.getOutputStream()) &#123;        // 设置头部信息        response.setHeader(            &quot;Content-disposition&quot;,            &quot;attachment;filename=&quot;            + new String((name + &quot;.xlsx&quot;).getBytes(StandardCharsets.UTF_8), StandardCharsets.ISO_8859_1));        //循环将输入流中的内容读取到缓冲区当中        while ((len = in.read(buffer)) &gt; 0) &#123;            //输出缓冲区的内容到浏览器，实现文件下载            out.write(buffer, 0, len);        &#125;    &#125; catch (Exception e) &#123;        e.printStackTrace();    &#125;&#125;
